SELECT user_id AS userId, SUM(amount) AS amount
FROM u_user_coin_record
WHERE biz_time >= #{start}
  AND biz_time < #{end}
  AND direction = 1
  AND is_deleted = 0
GROUP BY user_id
ORDER BY amount DESC
LIMIT #{limit}

SELECT user_id AS userId, SUM(amount) AS amount
FROM u_user_coin_record
WHERE biz_time >= #{start}
  AND biz_time < #{end}
  AND direction = 1
  AND is_deleted = 0
  AND user_id = #{userId}
GROUP BY user_id
